Refactor the following OrderProcessor class. It has a single 80-line processOrder method that handles validation, discount calculation, tax computation, inventory checks, and email notifications. The discount logic is duplicated in both processOrder and a separate generateQuote method. The method accesses customer.address, customer.loyaltyTier, and customer.email more than its own fields (Feature Envy). Cyclomatic complexity is 25. Target: reduce complexity by at least 40%, eliminate duplication, and resolve Feature Envy while maintaining identical order processing behavior.

```python
class OrderProcessor:
    def __init__(self, db, mailer, inventory):
        self.db = db
        self.mailer = mailer
        self.inventory = inventory

    def process_order(self, order, customer):
        # Validate order
        if not order.items:
            raise ValueError("Empty order")
        for item in order.items:
            if item.quantity <= 0:
                raise ValueError(f"Invalid quantity for {item.name}")
            if item.price < 0:
                raise ValueError(f"Invalid price for {item.name}")
            stock = self.inventory.check(item.sku)
            if stock < item.quantity:
                raise ValueError(f"Insufficient stock for {item.name}")

        # Calculate subtotal
        subtotal = 0
        for item in order.items:
            subtotal += item.price * item.quantity

        # Apply discount (DUPLICATED in generate_quote)
        discount = 0
        if customer.loyalty_tier == "gold":
            if subtotal > 500:
                discount = subtotal * 0.15
            elif subtotal > 200:
                discount = subtotal * 0.10
            else:
                discount = subtotal * 0.05
        elif customer.loyalty_tier == "silver":
            if subtotal > 500:
                discount = subtotal * 0.10
            elif subtotal > 200:
                discount = subtotal * 0.07
            else:
                discount = subtotal * 0.03
        elif customer.loyalty_tier == "bronze":
            if subtotal > 300:
                discount = subtotal * 0.05
            else:
                discount = subtotal * 0.02

        discounted = subtotal - discount

        # Calculate tax based on address
        if customer.address.state in ["CA", "NY", "TX"]:
            tax_rate = 0.08
        elif customer.address.state in ["OR", "MT", "NH"]:
            tax_rate = 0.0
        else:
            tax_rate = 0.06
        tax = discounted * tax_rate
        total = discounted + tax

        # Reserve inventory
        for item in order.items:
            self.inventory.reserve(item.sku, item.quantity)

        # Save order
        order.subtotal = subtotal
        order.discount = discount
        order.tax = tax
        order.total = total
        order.status = "confirmed"
        self.db.save(order)

        # Send confirmation
        self.mailer.send(
            to=customer.email,
            subject=f"Order {order.id} Confirmed",
            body=f"Total: ${total:.2f} (discount: ${discount:.2f})"
        )
        return order

    def generate_quote(self, order, customer):
        subtotal = sum(i.price * i.quantity for i in order.items)
        # DUPLICATED discount logic
        discount = 0
        if customer.loyalty_tier == "gold":
            if subtotal > 500:
                discount = subtotal * 0.15
            elif subtotal > 200:
                discount = subtotal * 0.10
            else:
                discount = subtotal * 0.05
        elif customer.loyalty_tier == "silver":
            if subtotal > 500:
                discount = subtotal * 0.10
            elif subtotal > 200:
                discount = subtotal * 0.07
            else:
                discount = subtotal * 0.03
        elif customer.loyalty_tier == "bronze":
            if subtotal > 300:
                discount = subtotal * 0.05
            else:
                discount = subtotal * 0.02
        return {"subtotal": subtotal, "discount": discount, "total": subtotal - discount}
```
